// ─── Seed Function ───────────────────────────────────────────────────────────
export function seedDatabase(): void {
  initDb();
  const db = getDb();

  const badgeCount = db.prepare('SELECT COUNT(*) as count FROM badges').get() as { count: number };
  if (badgeCount.count > 0) {
    console.log('Database already seeded. Skipping.');
    return;
  }

  console.log('Seeding database...');

  try {
    db.exec('BEGIN TRANSACTION');

    // ── Languages ──
    const langs = [
      { code: 'english', name: 'English', flag: '🇬🇧' },
      { code: 'french', name: 'Français', flag: '🇫🇷' },
      { code: 'spanish', name: 'Español', flag: '🇪🇸' },
      { code: 'russian', name: 'Русский', flag: '🇷🇺' },
      { code: 'german', name: 'Deutsch', flag: '🇩🇪' },
    ];
    const insertLang = db.prepare('INSERT INTO languages (code, name, flag_emoji) VALUES (?, ?, ?)');
    for (const l of langs) insertLang.run(l.code, l.name, l.flag);

    // ── Badges ──
    const badges = [
      ['初来乍到', 'rocket', '完成你的第一节课程', 'complete_first_lesson'],
      ['连续打卡7天', 'flame', '连续学习7天', 'streak_7'],
      ['连续打卡30天', 'zap', '连续学习30天', 'streak_30'],
      ['单词达人', 'book-open', '掌握100个单词', 'master_100_words'],
      ['语法专家', 'check-circle', '完成50道语法题', 'complete_50_grammar'],
      ['听力高手', 'headphones', '完成20次听力训练', 'complete_20_listening'],
      ['口语新星', 'mic', '完成10次口语跟读', 'complete_10_speaking'],
      ['积分收割机', 'trophy', '累计获得1000经验值', 'xp_1000'],
      ['挑战达人', 'target', '完成7次每日挑战', 'complete_7_challenges'],
      ['学霸', 'graduation-cap', '完成5门课程', 'complete_5_courses'],
    ];
    const insertBadge = db.prepare('INSERT INTO badges (name, icon, description, condition) VALUES (?, ?, ?, ?)');
    for (const b of badges) insertBadge.run(b[0], b[1], b[2], b[3]);

    // ── Courses, Units, Lessons, Content ──
    const langKeys = ['english', 'french', 'spanish', 'russian', 'german'] as const;
    const lessonTypes = ['word', 'grammar', 'listening', 'speaking'] as const;
    const lessonDurations = { word: 10, grammar: 15, listening: 10, speaking: 12 };

    const insertCourse = db.prepare('INSERT INTO courses (language_id, title, description, level, cover_color, sort_order) VALUES (?, ?, ?, ?, ?, ?)');
    const insertUnit = db.prepare('INSERT INTO units (course_id, title, description, sort_order) VALUES (?, ?, ?, ?)');
    const insertLesson = db.prepare('INSERT INTO lessons (unit_id, title, type, duration_minutes, sort_order) VALUES (?, ?, ?, ?, ?)');
    const insertWord = db.prepare('INSERT INTO words (lesson_id, word, phonetic, translation, part_of_speech, example_sentence, example_translation) VALUES (?, ?, ?, ?, ?, ?, ?)');
    const insertGrammar = db.prepare('INSERT INTO grammar_questions (lesson_id, type, question, options_json, correct_answer, explanation) VALUES (?, ?, ?, ?, ?, ?)');
    const insertListening = db.prepare('INSERT INTO listening_questions (lesson_id, audio_url, transcript, type, question, options_json, correct_answer) VALUES (?, ?, ?, ?, ?, ?, ?)');
    const insertSpeaking = db.prepare('INSERT INTO speaking_prompts (lesson_id, text, translation, phonetic, audio_url, difficulty) VALUES (?, ?, ?, ?, ?, ?)');

    let colorIdx = 0;

    for (let li = 0; li < langKeys.length; li++) {
      const langKey = langKeys[li];
      const languageId = li + 1;

      for (let ci = 0; ci < LEVELS.length; ci++) {
        const level = LEVELS[ci];
        const courseTitle = `${COURSE_TITLES[langKey][ci]}`;
        const courseDesc = COURSE_DESCS[langKey][ci];
        const coverColor = COVER_COLORS[colorIdx % COVER_COLORS.length];
        colorIdx++;

        const courseResult = insertCourse.run(languageId, courseTitle, courseDesc, level, coverColor, ci + 1);
        const courseId = Number(courseResult.lastInsertRowid);

        for (let ui = 0; ui < UNIT_TITLES.length; ui++) {
          const unitTitle = UNIT_TITLES[ui];
          const unitDesc = UNIT_DESCS[langKey][ui];

          const unitResult = insertUnit.run(courseId, unitTitle, unitDesc, ui + 1);
          const unitId = Number(unitResult.lastInsertRowid);

          for (let lti = 0; lti < lessonTypes.length; lti++) {
            const lessonType = lessonTypes[lti];
            const lessonTitleMap = LESSON_TITLES[lessonType] as Record<string, string[]>;
            const lessonTitle = lessonTitleMap[langKey][ui];

            const lessonResult = insertLesson.run(unitId, lessonTitle, lessonType, lessonDurations[lessonType], lti + 1);
            const lessonId = Number(lessonResult.lastInsertRowid);

            // Insert content based on lesson type
            if (lessonType === 'word') {
              const words = wordBanks[langKey]?.[ci]?.[ui];
              if (words) {
                for (const w of words) {
                  insertWord.run(lessonId, w.word, w.phonetic, w.translation, w.pos, w.example, w.exampleTrans);
                }
              }
            } else if (lessonType === 'grammar') {
              const grammars = grammarBanks[langKey]?.[ci]?.[ui];
              if (grammars) {
                for (const g of grammars) {
                  insertGrammar.run(lessonId, g.type, g.question, JSON.stringify(g.options), g.correct, g.explanation);
                }
              }
            } else if (lessonType === 'listening') {
              const listens = listeningBanks[langKey]?.[ci]?.[ui];
              if (listens) {
                for (const l of listens) {
                  insertListening.run(lessonId, l.audio_url, l.transcript, l.type, l.question, JSON.stringify(l.options), l.correct);
                }
              }
            } else if (lessonType === 'speaking') {
              const speaks = speakingBanks[langKey]?.[ci]?.[ui];
              if (speaks) {
                for (const s of speaks) {
                  insertSpeaking.run(lessonId, s.text, s.translation, s.phonetic, s.audio_url, s.difficulty);
                }
              }
            }
          }
        }
      }
    }

    db.exec('COMMIT');
    console.log('Database seeded successfully!');
  } catch (err) {
    db.exec('ROLLBACK');
    console.error('Seeding failed:', err);
    throw err;
  }
}

seedDatabase();
